/******************************************
* Interfaces.ts
* Defines interfaces required by the controller
* and MLS services.
*******************************************/

import Stream from "mithril/stream"

// ts-mls types
import { type KeyPackage } from "ts-mls"

// ActivityStreams types
import { type Activity } from "../as/activity"
import { type Document } from "../as/document"
import { type Actor } from "../as/actor"

// Model types
import { type Config } from "../model/config"
import { type Contact } from "../model/contact"
import { type Filter } from "../model/filter"
import { type Group, type EncryptedGroup, type GroupState } from "../model/group"
import { type Message } from "../model/message"
import { type DBKeyPackage } from "../model/db-keypackage"
import type { Collection } from "../as/collection"

// ICodec wraps all of the encoding/decoding methods 
// for generating and managing messages.  The MLS codec
// generates MLS messages, and the Plaintext codec sends
// regular ActivityPub "direct messages".
export interface ICodec {
	createGroup(newMembers: string[]): Promise<Group>
	encodeMessage(group: Group, message: Message): Promise<{}>
	getGroup(groupId: string): Promise<Group>
	getGroupMembers(group: Group): string[]
	addGroupMembers(group: Group, newMembers: string[]): Promise<Group>
	leaveGroup(group: Group): Promise<void>
	removeGroupMember(group: Group, actorId: string): Promise<void>
	receiveActivity(activity: Activity): Promise<Activity | undefined>
	sendActivity(group: Group, activity: Activity): Promise<string>
}

export interface IContacts {
	getContactStream(id: string): Stream<Contact>
	loadContact(id: string): Promise<Contact | undefined>
	saveContact(contact: Contact): void
	stop(): void
}

export interface IController {

	// Lifecycle methods
	stop(message: string): void

	createOrUpdateKeyPackage(): Promise<DBKeyPackage>
}

// IDatabase wraps all of the methods that the MLS service
// uses to store group state.
export interface IDatabase {

	// Lifecycle methods
	stop(): void
	erase(): void

	// Config methods
	loadConfig(): Promise<Config>
	saveConfig(config: Config): Promise<void>

	// Group methods
	allGroups(): Promise<(Group | EncryptedGroup)[]>
	searchGroups(tags: string[], stateIds?: GroupState[]): Promise<Group[]>
	loadGroup(groupId: string): Promise<Group | EncryptedGroup | undefined>
	saveGroup(group: Group): Promise<void>
	deleteGroup(groupId: string): Promise<void>

	// Filter methods
	allFilters(): Promise<Filter[]>
	loadFilter(filterId: string): Promise<Filter | undefined>
	saveFilter(filter: Filter): Promise<void>
	deleteFilter(filterId: string): Promise<void>

	// KeyPackage methods
	loadKeyPackage(): Promise<DBKeyPackage | undefined>
	saveKeyPackage(dbKeyPackage: DBKeyPackage): Promise<DBKeyPackage>
	deleteKeyPackage(): Promise<void>

	// Message methods
	allMessages(groupId: string): Promise<Message[]>
	getFirstMessageInGroup(groupId: string): Promise<Message | undefined>
	loadMessage(messageId: string): Promise<Message>
	saveMessage(message: Message): Promise<void>
	deleteMessage(messageId: string): Promise<void>
	deleteMessagesByGroup(groupId: string): Promise<void>

	// Like/Undo methods
	likeMessage(actorId: string, messageId: string, content: string): Promise<Message | undefined>
	undoLikeMessage(actorId: string, messageId: string): Promise<Message | undefined>

	// other event handlers
	onchange(handler: () => void): void
}

// IDelivery wraps all of the methods that the MLS service
// uses to send messages.
export interface IDelivery {

	// Lifecycle methods
	stop(): void

	// Lifecycle methods
	setActor(actor: Actor): void
	setSignout(onSignout: () => void): void

	// sendActivity sends a raw ActivityStream activity to the server for delivery.
	sendActivity(activity: Activity): Promise<string>
}

// IDirectory wraps all of the methods that the MLS service
// uses to look up users' KeyPackages.
export interface IDirectory {

	// Lifecycle methods
	stop(): void

	// Lifecycle methods
	setActor(actor: Actor): void

	// KeyPackage methods
	getKeyPackagesByActor(actorId: string): AsyncGenerator<Document>
	getKeyPackages(actorIDs: string[]): Promise<KeyPackage[]>
	createKeyPackage(dbKeyPackage: DBKeyPackage): Promise<[string, string]>
	updateKeyPackage(dbKeyPackage: DBKeyPackage): Promise<void>
	deleteKeyPackage(keyPackageUrl: string): Promise<void>
}

// IHost wraps methods that integrate with the host application, such as viewing an actor's profile
// or managing keypackages on the server
export interface IHost {
	notify(title: string, message: string): void
	reload(): void
	viewActor(actorId: string): void
	viewBlockActor(actorId: string): void
	viewKeyPackages(): void
	viewBlockActor(actorId: string): void
}

export interface IProxy {
	setProxyUrl(proxyUrl: string): void
	Activity(url: string): Promise<Activity>
	Actor(url: string): Promise<Actor>
	Document(url: string): Promise<Document>
	Collection(url: string): Promise<Collection>
}

// IWebFinger resolves fediverse handles (@user@host) into the actor's profile URL.
export interface IWebFinger {
	resolveActorURL(handle: string): Promise<string>
}

// IReceiver wraps all of the methods that the Controller uses
// to receive SSE updates.
export interface IReceiver {

	// Lifecycle methods
	setActor(actor: Actor): void
	start(generatorId: string, handler: IActivityHandler, lastMessageGetterSetter: ILastMessageGetterSetter, onSignout: () => void): void
	stop(): void
}

// IActivityHandler is a function that takes an MlsPrivateMessage and returns void.
// The Receiver service will call the registered ActivityHandler when a new message
// is received.
export type IActivityHandler = (activity: Activity) => Promise<void>


// ILastMessageHandler is a function that gets or sets the last message ID.
// The Receiver service will call the registered LastMessageHandler to get the ID
// of the last message received, and to update it when new messages are received.
export type ILastMessageGetterSetter = (messageId?: string) => Promise<string>
